export function parseBoolean(raw: string | undefined, defaultValue: boolean): boolean {
  if (raw === undefined || raw === null || String(raw).trim() === '') return defaultValue;
  const v = String(raw).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'on'].includes(v)) return true;
  if (['false', '0', 'no', 'n', 'off'].includes(v)) return false;
  throw new Error(`Invalid boolean: ${raw}`);
}

export function parseEnum<T extends string>(field: string, raw: string, allowed: readonly T[]): T {
  const v = String(raw ?? '').trim();
  if (!allowed.includes(v as T)) {
    throw new Error(`Invalid ${field}: ${raw}. Allowed: ${allowed.join(', ')}`);
  }
  return v as T;
}

export function normalizeSha256Digest(raw: string): string {
  const s = String(raw ?? '').trim();
  const m = s.match(/sha256:([a-f0-9]{64})/i) ?? s.match(/^([a-f0-9]{64})$/i);
  if (!m) throw new Error(`Invalid sha256 digest: ${raw}`);
  return `sha256:${m[1]!.toLowerCase()}`;
}

export function requireNonEmpty(value: string, fieldName: string): string {
  const v = String(value ?? '').trim();
  if (!v) throw new Error(`Missing required ${fieldName}`);
  return v;
}

export function firstNonEmpty(...values: (string | undefined)[]): string {
  for (const v of values) {
    const s = String(v ?? '').trim();
    if (s) return s;
  }
  return '';
}
